@startuml
skinparam classDiagram
    class CQLSessionException {
        +CQLSessionException()
    }
    class CassandraDBFactory {
        +create()
        +getCassandraDB()
        +CassandraDBFactory()
    }
    class CassandraDB {
        contactPoints : Vector<InetSocketAddress>
        cqlSession : CqlSession
        datacenter : String
        hostnames : Array<String>
        ports : Array<Integer>
        connect()
        disconnect()
        execute()
        prepareStatement()
        query()
        query()
        CassandraDB()
    }
    class Main {
        main()
        testAggregation()
    }
    class DBFactory {
        +DBFactory()
    }
    class DB {
        +DB()
    }
    class Cassandra {
        +CassandraDB()
    }
    class it {
    }
    class unipi {
    }
    class Ismsdb {
    }
    class stocksim {
    }
    class lib {
    }
    class database {
    }
    class cassandra {
    }

    it --> unipi
    unipi --> Ismsdb
    Ismsdb --> stocksim
    stocksim --> lib
    lib --> database
    database --> cassandra
    cassandra --> CassandraDB
    cassandra --> CassandraDBFactory
    cassandra --> CQLSessionException
    cassandra --> DBFactory
    cassandra --> DB
    cassandra --> Main

    CQLSessionException --> CQLSessionException
    CassandraDBFactory --> create
    CassandraDBFactory --> getCassandraDB
    CassandraDBFactory --> CassandraDBFactory
    CassandraDB --> contactPoints
    CassandraDB --> cqlSession
    CassandraDB --> datacenter
    CassandraDB --> hostnames
    CassandraDB --> ports
    CassandraDB --> connect
    CassandraDB --> disconnect
    CassandraDB --> execute
    CassandraDB --> prepareStatement
    CassandraDB --> query
    CassandraDB --> query
    CassandraDB --> CassandraDB
    Main --> main
    Main --> testAggregation
    DBFactory --> DBFactory
    DB --> DB
    Cassandra --> CassandraDB
@enduml
